    dev.htod_sync_copy_into(&rgb_f32, &mut res.d_rgb_in)
        .map_err(map_cudarc_error)?;
    dev.htod_sync_copy_into(depth, &mut res.d_depth)
        .map_err(map_cudarc_error)?;
}

